// ─── API ───
async function callAPI(sys, usr) {
  try {
    const body = { model:"claude-sonnet-4-20250514", max_tokens:4096, system:sys, messages:[{role:"user",content:usr}] };
    const res = await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)});
    if(!res.ok) throw new Error(`API ${res.status}`);
    const data = await res.json();
    if(data.error) throw new Error(data.error.message);
    return (data.content||[]).filter(b=>b.type==="text").map(b=>b.text).join("\n")||"";
  } catch(e) { return "⚠ "+e.message; }
}

function parseJSON(raw) {
  if(!raw||raw.startsWith("⚠")) return null;
  try { const t=raw.trim(); if(t.startsWith("[")) return JSON.parse(t); } catch{}
  try { const c=raw.replace(/```json\s*/g,"").replace(/```\s*/g,"").trim(); const m=c.match(/\[\s*\{[\s\S]*\}\s*\]/); if(m) return JSON.parse(m[0]); } catch{}
  try { const s=raw.indexOf("["),e=raw.lastIndexOf("]"); if(s!==-1&&e>s) return JSON.parse(raw.substring(s,e+1)); } catch{}
  return null;
}

// ─── STORAGE ───
const ST = {
  async get(k) { try { const v=localStorage.getItem(k); return v?JSON.parse(v):null; } catch{return null;} },
  async set(k,v) { try { localStorage.setItem(k,JSON.stringify(v)); } catch{} },
  async delete(k) { try { localStorage.removeItem(k); } catch{} },
  async list(prefix) { try { const keys=[]; for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i); if(k.startsWith(prefix)) keys.push(k);} return keys; } catch{return [];} },
};

// ─── COMPONENTS ───
function Loading({text}) { return <div className="ld"><div className="dots"><span/><span/><span/></div><span style={{fontSize:12,color:"var(--t2)"}}>{text||"處理中..."}</span></div>; }

function Modal({title,children,onClose,width}) {
  return <div className="mo" onClick={onClose}><div className="md fin" onClick={e=>e.stopPropagation()} style={width?{width}:{}}><div className="md-t">{title}</div>{children}</div></div>;
}

function ClientModal({client,onSave,onClose,onDelete}) {
  const [f,sF]=useState(client||{name:"",category:"",tone:"",audience:"",keywords:"",notes:""});
  const s=(k,v)=>sF(p=>({...p,[k]:v}));
  return <Modal title={client?"編輯客戶":"新增客戶"} onClose={onClose}>
    <div className="fg"><label className="fl">品牌名稱 *</label><input className="fi" value={f.name} onChange={e=>s("name",e.target.value)} placeholder="例：ABC Coffee"/></div>
    <div className="fg"><label className="fl">類別 *</label><select className="fs" value={f.category} onChange={e=>s("category",e.target.value)}><option value="">選擇</option>{CATEGORIES.map(c=><option key={c}>{c}</option>)}</select></div>
    <div className="fg"><label className="fl">品牌調性</label><textarea className="ft" value={f.tone} onChange={e=>s("tone",e.target.value)} placeholder="例：專業但親切，避免太多術語"/></div>
    <div className="fg"><label className="fl">目標受眾</label><input className="fi" value={f.audience} onChange={e=>s("audience",e.target.value)} placeholder="例：25-40歲都市女性"/></div>
    <div className="fg"><label className="fl">關鍵詞</label><input className="fi" value={f.keywords} onChange={e=>s("keywords",e.target.value)} placeholder="逗號分隔"/></div>
    <div className="fg"><label className="fl">備註</label><textarea className="ft" value={f.notes} onChange={e=>s("notes",e.target.value)} style={{minHeight:40}}/></div>
    <div className="md-a">
      {client&&<button className="btn bd bsm" onClick={()=>onDelete(client.id)} style={{marginRight:"auto"}}>刪除</button>}
      <button className="btn bs" onClick={onClose}>取消</button>
      <button className="btn bp" disabled={!f.name||!f.category} onClick={()=>onSave({...f,id:client?.id||Date.now().toString()})}>{client?"儲存":"新增"}</button>
    </div>
  </Modal>;
}

// ═══════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════

function TemplateModal({tpl,onSave,onClose}) {
  const [f,sF]=useState(tpl||{name:"",description:"",prompt:""});
  const s=(k,v)=>sF(p=>({...p,[k]:v}));
  return <Modal title={tpl?"編輯模板":"新增模板"} onClose={onClose}>
    <div className="fg"><label className="fl">模板名稱</label><input className="fi" value={f.name} onChange={e=>s("name",e.target.value)} placeholder="例：品牌故事風格"/></div>
    <div className="fg"><label className="fl">描述</label><input className="fi" value={f.description} onChange={e=>s("description",e.target.value)} placeholder="簡短描述用途"/></div>
    <div className="fg"><label className="fl">Prompt 指令</label><textarea className="ft" value={f.prompt} onChange={e=>s("prompt",e.target.value)} placeholder="輸入完整 Prompt 指令，生成時會取代預設 system prompt..." style={{minHeight:120}}/></div>
    <div className="md-a"><button className="btn bs" onClick={onClose}>取消</button><button className="btn bp" disabled={!f.name||!f.prompt} onClick={()=>onSave({...f,id:tpl?.id||""})}>儲存</button></div>
  </Modal>;
}

function ScheduleModal({item,onSave,onClose,clientName,clientCategory}) {
  const [f,sF]=useState({date:item.date||"",title:"",platform:item.platform||"facebook",note:""});
  const [titleSugs,setTitleSugs]=useState([]);
  const [titleLoad,setTitleLoad]=useState(false);
  const [customMode,setCustomMode]=useState(false);
  const s=(k,v)=>sF(p=>({...p,[k]:v}));

  // Generate title suggestions on mount
  useEffect(()=>{
    if(!item.content) return;
    (async()=>{
      setTitleLoad(true);
      const sys=`You generate short calendar titles for social media posts. Return ONLY a JSON array of 5 strings. Each title should be 5-15 characters in Traditional Chinese, concise and descriptive. No other text.`;
      const usr=`Based on this social media post content, suggest 5 short calendar event titles:\n\n${item.content.substring(0,500)}\n\nBrand: ${clientName||""}(${clientCategory||""}). JSON array of 5 strings only.`;
      try {
        const raw=await callAPI(sys,usr);
        const cleaned=raw.replace(/```json\s*/g,"").replace(/```\s*/g,"").trim();
        let arr=null;
        try{arr=JSON.parse(cleaned);}catch{}
        if(!arr){try{const m=cleaned.match(/\[[\s\S]*\]/);if(m)arr=JSON.parse(m[0]);}catch{}}
        if(arr&&Array.isArray(arr)) setTitleSugs(arr.filter(x=>typeof x==="string").slice(0,5));
      } catch{}
      setTitleLoad(false);
    })();
  },[]);

  return <Modal title="排入日曆" onClose={onClose} width="480px">
    <div className="fg"><label className="fl">日期</label><input className="fi" type="date" value={f.date} onChange={e=>s("date",e.target.value)}/></div>

    <div className="fg">
      <label className="fl">標題</label>
      {titleLoad&&<div style={{display:"flex",alignItems:"center",gap:6,marginBottom:8}}><div className="dots"><span/><span/><span/></div><span style={{fontSize:11,color:"var(--t2)"}}>AI 建議標題中...</span></div>}
      {titleSugs.length>0&&!customMode&&<div style={{display:"flex",flexDirection:"column",gap:4,marginBottom:8}}>
        {titleSugs.map((t,i)=><button key={i} onClick={()=>s("title",t)} style={{
          padding:"8px 12px",borderRadius:7,border:`1px solid ${f.title===t?"var(--ac)":"var(--bd)"}`,
          background:f.title===t?"var(--ac15)":"var(--b3)",color:f.title===t?"var(--ac)":"var(--t1)",
          fontSize:13,textAlign:"left",cursor:"pointer",fontFamily:"inherit",transition:"all .1s"
        }}>{t}</button>)}
        <button onClick={()=>{setCustomMode(true);s("title","");}} style={{
          padding:"8px 12px",borderRadius:7,border:"1px dashed var(--bd)",
          background:"transparent",color:"var(--t3)",fontSize:12,textAlign:"left",cursor:"pointer",fontFamily:"inherit",transition:"all .1s"
        }}>✏️ 自己輸入標題...</button>
      </div>}
      {(customMode||titleSugs.length===0&&!titleLoad)&&<>
        <input className="fi" value={f.title} onChange={e=>s("title",e.target.value)} placeholder="輸入內容標題"/>
        {titleSugs.length>0&&<button onClick={()=>setCustomMode(false)} style={{fontSize:10,color:"var(--ac)",background:"none",border:"none",cursor:"pointer",marginTop:4,fontFamily:"inherit"}}>← 返回建議選項</button>}
      </>}
    </div>

    <div className="fg"><label className="fl">平台</label><select className="fs" value={f.platform} onChange={e=>s("platform",e.target.value)}>{PLATFORMS.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}</select></div>
    <div className="fg"><label className="fl">備註</label><textarea className="ft" value={f.note} onChange={e=>s("note",e.target.value)} style={{minHeight:40}} placeholder="可選：補充說明"/></div>
    <div className="md-a"><button className="btn bs" onClick={onClose}>取消</button><button className="btn bp" disabled={!f.date||!f.title} onClick={()=>onSave({...f,content:item.content||""})}>確認排期</button></div>
  </Modal>;
}

export default function App() {
  const [clients,setClients]=useState([]);
  const [ac,setAc]=useState(null);
  const [tab,setTab]=useState("dashboard");
  const [modal,setModal]=useState(null); // null | "client" | "template"
  const [editCl,setEditCl]=useState(null);

  // Discover
  const [trendLoad,setTrendLoad]=useState(false);
  const [trends,setTrends]=useState([]);
  const [selTopics,setSelTopics]=useState([]);

  // Generate
  const [plat,setPlat]=useState(null);
  const [fmt,setFmt]=useState("");
  const [lang,setLang]=useState("tc");
  const [len,setLen]=useState("medium");
  const [genLoad,setGenLoad]=useState(false);
  const [output,setOutput]=useState("");
  const [copied,setCopied]=useState(false);
  const [customBrief,setCustomBrief]=useState("");
  const [customGoal,setCustomGoal]=useState("");

  // AI Image
  const [imgLoad,setImgLoad]=useState(false);
  const [imgSugs,setImgSugs]=useState([]);

  // Multi-platform
  const [multiLoad,setMultiLoad]=useState(false);
  const [multiOutputs,setMultiOutputs]=useState([]);

  // History
  const [history,setHistory]=useState([]);
  const [historyView,setHistoryView]=useState(null);

  // Calendar
  const [calMonth,setCalMonth]=useState(()=>{const d=new Date();return{y:d.getFullYear(),m:d.getMonth()};});
  const [calEvents,setCalEvents]=useState([]);
  const [scheduleItem,setScheduleItem]=useState(null);

  // Templates
  const [templates,setTemplates]=useState([]);
  const [editTpl,setEditTpl]=useState(null);

  // Competitors
  const [compLoad,setCompLoad]=useState(false);
  const [compResults,setCompResults]=useState([]);
  const [compList,setCompList]=useState([]); // saved competitor names
  const [compInput,setCompInput]=useState("");

  // ─── LOAD DATA ───
  useEffect(()=>{
    (async()=>{
      const cl=await ST.get("flux_clients")||[];
      setClients(cl);
      if(cl.length) setAc(cl[0]);
      setTemplates(await ST.get("flux_templates")||[]);
    })();
  },[]);

  // Load per-client data
  useEffect(()=>{
    if(!ac) return;
    (async()=>{
      setHistory(await ST.get("flux_hist_"+ac.id)||[]);
      setCalEvents(await ST.get("flux_cal_"+ac.id)||[]);
      setCompList(await ST.get("flux_comp_"+ac.id)||[]);
      setCompResults([]);
    })();
  },[ac?.id]);

  // ─── CLIENT CRUD ───
  const saveCl=async(c)=>{
    const up=clients.find(x=>x.id===c.id)?clients.map(x=>x.id===c.id?c:x):[...clients,c];
    setClients(up);setAc(c);await ST.set("flux_clients",up);setModal(null);setEditCl(null);
  };
  const delCl=async(id)=>{
    const up=clients.filter(x=>x.id!==id);
    setClients(up);if(ac?.id===id)setAc(up[0]||null);await ST.set("flux_clients",up);setModal(null);setEditCl(null);
  };

  // ─── SAVE HISTORY ───
  const addHistory=async(item)=>{
    if(!ac) return;
    const h=[{...item,id:Date.now().toString(),date:new Date().toISOString()},...history].slice(0,100);
    setHistory(h);await ST.set("flux_hist_"+ac.id,h);
  };

  // ─── SAVE CALENDAR ───
  const addCalEvent=async(ev)=>{
    if(!ac)return;
    const c=[...calEvents,{...ev,id:Date.now().toString()}];
    setCalEvents(c);await ST.set("flux_cal_"+ac.id,c);
  };
  const delCalEvent=async(id)=>{
    const c=calEvents.filter(x=>x.id!==id);
    setCalEvents(c);await ST.set("flux_cal_"+ac.id,c);
  };

  // ─── TEMPLATE CRUD ───
  const saveTpl=async(t)=>{
    const up=templates.find(x=>x.id===t.id)?templates.map(x=>x.id===t.id?t:x):[...templates,{...t,id:Date.now().toString()}];
    setTemplates(up);await ST.set("flux_templates",up);setEditTpl(null);setModal(null);
  };
  const delTpl=async(id)=>{
    const up=templates.filter(x=>x.id!==id);
    setTemplates(up);await ST.set("flux_templates",up);setEditTpl(null);setModal(null);
  };

  // ─── BACKUP EXPORT / IMPORT ───
  const exportBackup=async()=>{
    const backup={version:"2.0",date:new Date().toISOString(),clients,templates};
    // Collect per-client data
    for(const c of clients){
      backup["hist_"+c.id]=await ST.get("flux_hist_"+c.id)||[];
      backup["cal_"+c.id]=await ST.get("flux_cal_"+c.id)||[];
      backup["comp_"+c.id]=await ST.get("flux_comp_"+c.id)||[];
    }
    const blob=new Blob([JSON.stringify(backup,null,2)],{type:"application/json"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");
    a.href=url;a.download="flux-backup-"+new Date().toISOString().split("T")[0]+".json";
    a.click();URL.revokeObjectURL(url);
  };

  const importBackup=(file)=>{
    const reader=new FileReader();
    reader.onload=async(e)=>{
      try{
        const data=JSON.parse(e.target.result);
        if(!data.clients)throw new Error("無效嘅備份檔案");
        // Restore clients
        setClients(data.clients);await ST.set("flux_clients",data.clients);
        // Restore templates
        if(data.templates){setTemplates(data.templates);await ST.set("flux_templates",data.templates);}
        // Restore per-client data
        for(const c of data.clients){
          if(data["hist_"+c.id])await ST.set("flux_hist_"+c.id,data["hist_"+c.id]);
          if(data["cal_"+c.id])await ST.set("flux_cal_"+c.id,data["cal_"+c.id]);
          if(data["comp_"+c.id])await ST.set("flux_comp_"+c.id,data["comp_"+c.id]);
        }
        setAc(data.clients[0]||null);
        setModal(null);
        alert("✅ 已成功匯入 "+data.clients.length+" 個客戶！");
      }catch(err){alert("⚠ 匯入失敗："+err.message);}
    };
    reader.readAsText(file);
  };

  // ─── DISCOVER TRENDS ───
  const [trendMeta,setTrendMeta]=useState(null);
  const discover=async()=>{
    if(!ac)return;
    setTrendLoad(true);setTrends([]);setSelTopics([]);setTrendMeta(null);
    const todayStr=new Date().toISOString().split("T")[0];
    const sys=`You are a social media strategist for the ${ac.category} industry. Today is ${todayStr}. Respond with ONLY a JSON array of 8 objects, no other text. Keys: "title"(string),"description"(string,1-2 sentences),"angle"(string),"tag"("trending"|"seasonal"|"evergreen").`;
    const usr=`Generate trending topics for "${ac.name}" (${ac.category}). Tone:${ac.tone||"professional"}. Audience:${ac.audience||"general"}. Keywords:${ac.keywords||"N/A"}. Mix 3 trending, 3 seasonal, 2 evergreen. Traditional Chinese. JSON array only.`;
    let parsed=null;
    try{parsed=parseJSON(await callAPI(sys,usr));}catch{}
    const now=new Date();
    const timeStr=now.toLocaleDateString("zh-TW",{year:"numeric",month:"long",day:"numeric"})+" "+now.toLocaleTimeString("zh-TW",{hour:"2-digit",minute:"2-digit"});
    setTrendMeta({source:"local",time:timeStr});
    setTrends(parsed?.length?parsed:[{title:"暫時無法取得",description:"請稍後再試",angle:"",tag:"info"}]);
    setTrendLoad(false);
  };

  // ─── GENERATE CONTENT ───
  const generate=async(customPrompt)=>{
    if(!ac||!plat||!fmt)return;
    setGenLoad(true);setOutput("");setImgSugs([]);
    const p=PLATFORMS.find(x=>x.id===plat);
    const ln=LANGUAGES.find(x=>x.id===lang)?.name||"繁體中文";
    const le=LENGTHS.find(x=>x.id===len);

    // Build topic context: custom brief takes priority, then selected trends, then free
    let topicContext="自由發揮，根據品牌定位創作";
    if(customBrief.trim()){
      topicContext="【自訂主題】"+customBrief.trim();
      if(customGoal.trim()) topicContext+="\n【內容目標】"+customGoal.trim();
    } else if(selTopics.length>0){
      topicContext=selTopics.map(i=>trends[i]?.title+": "+trends[i]?.angle).join("\n");
    }

    const sys=customPrompt||"You are an expert social media content creator. Write directly as plain text. No JSON, no code blocks.";
    const usr=`Create a ${p.name} "${fmt}" post.
Brand:${ac.name}(${ac.category}) Tone:${ac.tone||"professional"} Audience:${ac.audience||"general"} Keywords:${ac.keywords||"N/A"}
Topic/Direction:${topicContext}
Platform:${p.name} Format:${fmt} Language:${ln} Length:${le.name}(${le.desc})
Include hashtags. Follow ${p.name} best practices. If Reels/視頻: scene descriptions+timing. If 微信長文: section headers. Match brand tone.`;
    const r=await callAPI(sys,usr);
    setOutput(r);setGenLoad(false);
    addHistory({platform:plat,format:fmt,language:lang,content:r,topics:customBrief.trim()?[customBrief.trim()]:selTopics.map(i=>trends[i]?.title).filter(Boolean)});
  };

  // ─── AI IMAGE SUGGESTIONS ───
  const suggestImages=async()=>{
    if(!output||!ac)return;
    setImgLoad(true);setImgSugs([]);
    const sys=`You are a visual content director. Return ONLY a JSON array of 4 objects. Keys: "direction"(string,visual direction in Chinese),"description"(string,detailed description),"midjourney_prompt"(string,English Midjourney prompt),"style"(string,e.g."flat illustration"|"photography"|"3D render"|"minimalist graphic")`;
    const usr=`Based on this social media post, suggest 4 image/visual directions:\n\nBrand:${ac.name}(${ac.category})\nPost content:\n${output.substring(0,600)}\n\nConsider brand tone:${ac.tone||"professional"}. Give diverse styles. JSON array only.`;
    const raw=await callAPI(sys,usr);
    const parsed=parseJSON(raw);
    setImgSugs(parsed||[]);
    setImgLoad(false);
  };

  // ─── MULTI-PLATFORM REWRITE ───
  const multiRewrite=async()=>{
    if(!output||!ac)return;
    setMultiLoad(true);setMultiOutputs([]);
    const sys=`You are a social media expert. Rewrite the given content for all 5 platforms. Return ONLY a JSON array of 5 objects. Keys: "platform"(string),"format"(string),"content"(string,the rewritten post). Platforms: Facebook(圖文貼文), Instagram(圖文貼文), Threads(短文), 小紅書(圖文筆記), 微信(朋友圈).`;
    const ln=LANGUAGES.find(x=>x.id===lang)?.name||"繁體中文";
    const usr=`Rewrite this content for all 5 platforms. Brand:${ac.name}. Tone:${ac.tone||"professional"}. Language:${ln}.\n\nOriginal:\n${output.substring(0,800)}\n\nAdapt length, style, hashtags for each platform. JSON array only.`;
    const raw=await callAPI(sys,usr);
    const parsed=parseJSON(raw);
    setMultiOutputs(parsed||[]);
    setMultiLoad(false);
    // Save all to history
    if(parsed) parsed.forEach(p=>addHistory({platform:p.platform,format:p.format,language:lang,content:p.content,topics:[]}));
  };

  // ─── COMPETITOR TRACKING ───
  const [selfAnalysis,setSelfAnalysis]=useState(null);
  const [compMeta,setCompMeta]=useState(null); // {source:"live"|"fallback", time:string}

  const addComp=async(name)=>{
    if(!ac||!name.trim()||compList.includes(name.trim()))return;
    const up=[...compList,name.trim()];
    setCompList(up);await ST.set("flux_comp_"+ac.id,up);
  };
  const removeComp=async(name)=>{
    if(!ac)return;
    const up=compList.filter(x=>x!==name);
    setCompList(up);await ST.set("flux_comp_"+ac.id,up);
  };

  const trackCompetitors=async()=>{
    if(!ac)return;
    setCompLoad(true);setCompResults([]);setSelfAnalysis(null);setCompMeta(null);
    const hasCustom=compList.length>0;
    const compContext=hasCustom?`Focus on these specific competitors: ${compList.join(", ")}. Analyze each one.`:`Find 6 notable competitors or industry leaders.`;
    const count=hasCustom?compList.length:6;
    const todayStr=new Date().toISOString().split("T")[0];

    const sys=`You are a competitive intelligence analyst. Today is ${todayStr}. Return ONLY a JSON object with two keys:
"self": an object analyzing OUR brand with keys: "strategy"(string,current content strategy assessment),"strength"(string),"weakness"(string),"recommendation"(string,top priority improvement).
"competitors": an array of ${count} objects, each with keys: "competitor"(string),"platform"(string),"strategy"(string),"strength"(string),"opportunity"(string,opportunity for our brand),"trend"(string).
No other text. JSON only.`;
    const usr=`Compare "${ac.name}" (${ac.category}) against its competitors.
Our brand tone: ${ac.tone||"N/A"}. Audience: ${ac.audience||"general"}. Keywords: ${ac.keywords||"N/A"}.
${compContext}
Analyze their social media presence and strategies across Facebook, Instagram, 小紅書, WeChat. Traditional Chinese. Return the JSON object only.`;
    
    let parsed=null;
    try {
      const raw=await callAPI(sys,usr);
      const cleaned=raw.replace(/```json\s*/g,"").replace(/```\s*/g,"").trim();
      try { const obj=JSON.parse(cleaned); if(obj.self&&obj.competitors){parsed=obj;} } catch{}
      if(!parsed){ try { const m=cleaned.match(/\{[\s\S]*\}/); if(m){const obj=JSON.parse(m[0]); if(obj.self&&obj.competitors) parsed=obj;} } catch{} }
    } catch{}
    
    const now=new Date();
    const timeStr=now.toLocaleDateString("zh-TW",{year:"numeric",month:"long",day:"numeric"})+" "+now.toLocaleTimeString("zh-TW",{hour:"2-digit",minute:"2-digit"});
    setCompMeta({source:"local",time:timeStr});
    if(parsed){
      setSelfAnalysis(parsed.self||null);
      setCompResults(parsed.competitors||[]);
    } else {
      setCompResults([]);
    }
    setCompLoad(false);
  };

  // ─── CALENDAR HELPERS ───
  const calDays=useMemo(()=>{
    const first=new Date(calMonth.y,calMonth.m,1);
    const startDay=first.getDay();
    const daysInMonth=new Date(calMonth.y,calMonth.m+1,0).getDate();
    const prevDays=new Date(calMonth.y,calMonth.m,0).getDate();
    const days=[];
    for(let i=startDay-1;i>=0;i--) days.push({d:prevDays-i,cur:false});
    for(let i=1;i<=daysInMonth;i++) days.push({d:i,cur:true});
    const rem=42-days.length;
    for(let i=1;i<=rem;i++) days.push({d:i,cur:false});
    return days;
  },[calMonth]);

  const today=new Date();
  const monthNames=["一月","二月","三月","四月","五月","六月","七月","八月","九月","十月","十一月","十二月"];

  const copy=(text)=>{navigator.clipboard.writeText(text);setCopied(true);setTimeout(()=>setCopied(false),1500);};

  // ═══════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════
  return(<>
    <style>{css}</style>
    <div className="app">
      {/* SIDEBAR */}
      <div className="sb">
        <div className="sb-h">
          <img src={LOGO_SRC} alt="Flux Strategy" style={{width:150,height:"auto",display:"block",filter:"brightness(1.1)"}} />
          <div style={{marginTop:10,fontSize:10,fontWeight:600,letterSpacing:".12em",color:"var(--t3)",textTransform:"uppercase"}}>Content Engine</div>
        </div>

        <div className="sb-cl">
          <div className="sl">客戶列表</div>
          {clients.map(c=>(
            <div key={c.id} className={`ci ${ac?.id===c.id?"on":""}`} onClick={()=>{setAc(c);setTrends([]);setOutput("");setSelTopics([]);setImgSugs([]);setMultiOutputs([]);setPlat(null);setFmt("");setLang("tc");setLen("medium");setCustomBrief("");setCustomGoal("");}}>
              <div className="ca" style={{background:CC[c.category]||"#555"}}>{c.name[0]}</div>
              <div><div className="cn">{c.name}</div><div className="cc">{c.category}</div></div>
            </div>
          ))}
          <button className="add-b" onClick={()=>{setEditCl(null);setModal("client");}}>+ 新增客戶</button>
        </div>

        <div className="sb-nav">
          {TABS.map(t=><button key={t.id} className={`nav-btn ${tab===t.id?"on":""}`} onClick={()=>setTab(t.id)}><span className="nav-ico">{t.ico}</span>{t.name}</button>)}
        </div>

        <div className="sb-f" style={{flexWrap:"wrap",gap:4,padding:"8px 10px"}}>
          <span style={{display:"flex",alignItems:"center",gap:4,flex:1}}><span className="dot" style={{background:"var(--grn)"}}/>v2.0</span>
          <button onClick={exportBackup} style={{background:"none",border:"1px solid var(--bd)",borderRadius:4,color:"var(--t3)",fontSize:9,padding:"2px 6px",cursor:"pointer",fontFamily:"inherit"}}>📤 備份</button>
          <label style={{background:"none",border:"1px solid var(--bd)",borderRadius:4,color:"var(--t3)",fontSize:9,padding:"2px 6px",cursor:"pointer"}}> 📥 匯入<input type="file" accept=".json" style={{display:"none"}} onChange={e=>{if(e.target.files[0])importBackup(e.target.files[0]);e.target.value="";}}/></label>
        </div>
      </div>

      {/* MAIN */}
      <div className="mn">
        <div className="mn-h">
          <div>{ac?<div className="gap6"><span style={{fontFamily:"'Fraunces',serif",fontSize:18}}>{ac.name}</span><span className="tag" style={{background:CC[ac.category],color:"#fff"}}>{ac.category}</span><button className="btn bs bsm" onClick={()=>{setEditCl(ac);setModal("client");}}>編輯</button></div>:<span style={{color:"var(--t3)",fontSize:12}}>請選擇或新增客戶</span>}</div>
          <div style={{fontSize:11,color:"var(--t3)"}}>{TABS.find(t=>t.id===tab)?.ico} {TABS.find(t=>t.id===tab)?.name}</div>
        </div>

        <div className="mn-b">
          {!ac ? (
            <div className="es"><div className="es-i">⚡</div><h3>開始使用 Content Engine</h3><p>在左側新增客戶，即可開始生成內容。</p></div>
          ) : tab==="dashboard" ? (
            /* ═══ DASHBOARD ═══ */
            <div className="fin">
              <div className="stat-grid">
                <div className="stat-card"><div className="stat-n" style={{color:"var(--ac)"}}>{history.length}</div><div className="stat-l">已生成內容</div></div>
                <div className="stat-card"><div className="stat-n" style={{color:"var(--blue)"}}>{calEvents.length}</div><div className="stat-l">排期內容</div></div>
                <div className="stat-card"><div className="stat-n" style={{color:"#F97316"}}>{[...new Set(history.map(h=>h.platform))].length}</div><div className="stat-l">已覆蓋平台</div></div>
                <div className="stat-card"><div className="stat-n" style={{color:"#EC4899"}}>{templates.length}</div><div className="stat-l">Prompt 模板</div></div>
              </div>

              {ac.tone&&<div className="cd" style={{borderLeft:"3px solid var(--ac)"}}><div style={{fontSize:11,fontWeight:600,color:"var(--ac)",marginBottom:4}}>品牌調性</div><div style={{fontSize:12,color:"var(--t2)",lineHeight:1.5}}>{ac.tone}</div>{ac.audience&&<div style={{fontSize:11,color:"var(--t3)",marginTop:5}}>🎯 {ac.audience}</div>}</div>}

              <div className="cd"><div className="cd-t">最近生成</div>
                {history.length===0?<div style={{fontSize:12,color:"var(--t3)"}}>尚未生成任何內容</div>:
                history.slice(0,5).map(h=><div key={h.id} className="hi" onClick={()=>{setHistoryView(h);}}><div className="between"><div className="gap6"><span className="opb" style={{background:PLATFORMS.find(p=>p.id===h.platform)?.color||"#555"}}>{h.platform}</span><span style={{fontSize:10,color:"var(--t3)"}}>{h.format}</span></div><span style={{fontSize:10,color:"var(--t3)"}}>{new Date(h.date).toLocaleDateString("zh-TW")}</span></div><div style={{fontSize:11,color:"var(--t2)",marginTop:5,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{h.content?.substring(0,80)}</div></div>)}
              </div>

              <div className="cd"><div className="cd-t">即將發佈</div>
                {calEvents.filter(e=>new Date(e.date)>=today).sort((a,b)=>new Date(a.date)-new Date(b.date)).slice(0,5).map(e=><div key={e.id} className="hi"><div className="between"><div className="gap6"><span className="opb" style={{background:PLATFORMS.find(p=>p.id===e.platform)?.color||"#555"}}>{e.platform}</span><span style={{fontSize:10,color:"var(--t1)"}}>{e.title}</span></div><span style={{fontSize:10,color:"var(--ac)"}}>{new Date(e.date).toLocaleDateString("zh-TW")}</span></div></div>)}
                {calEvents.filter(e=>new Date(e.date)>=today).length===0&&<div style={{fontSize:12,color:"var(--t3)"}}>暫無排期內容</div>}
              </div>
            </div>

          ) : tab==="discover" ? (
            /* ═══ DISCOVER ═══ */
            <div className="fin">
              <div className="cd">
                <div className="between mb12"><div className="cd-t" style={{margin:0}}>探索熱門話題</div><button className="btn bp" onClick={discover} disabled={trendLoad}>{trendLoad?"搜尋中...":"🔍 搜尋最新話題"}</button></div>
                {trendLoad&&<Loading text="搜尋熱門話題中..."/>}
                {trendMeta&&!trendLoad&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"6px 12px",marginBottom:10,borderRadius:6,background:trendMeta.source==="live"?"rgba(34,197,94,.08)":"rgba(239,68,68,.08)",border:`1px solid ${trendMeta.source==="live"?"rgba(34,197,94,.15)":"rgba(239,68,68,.15)"}`}}>
                  <span className="dot" style={{background:trendMeta.source==="live"?"var(--grn)":"var(--red)"}}/>
                  <span style={{fontSize:10,fontWeight:600,color:trendMeta.source==="live"?"var(--grn)":"var(--red)"}}>{trendMeta.source==="live"?"即時搜尋":"AI 知識庫"}</span>
                  <span style={{fontSize:10,color:"var(--t3)"}}>· {trendMeta.time}</span>
                </div>}
                {trends.length>0&&!trendLoad&&<>
                  <div style={{fontSize:11,color:"var(--t3)",marginBottom:8}}>點選話題（可多選）→ 到「生成內容」使用</div>
                  {trends.map((t,i)=><div key={i} className={`ti ${selTopics.includes(i)?"on":""}`} onClick={()=>setSelTopics(p=>p.includes(i)?p.filter(x=>x!==i):[...p,i])}><div className="between"><div className="tt">{t.title}</div><div className="tg">{t.tag}</div></div><div className="td">{t.description}</div>{t.angle&&<div style={{fontSize:11,color:"var(--ac)",marginTop:4,opacity:.85}}>💡 {t.angle}</div>}</div>)}
                  {selTopics.length>0&&<button className="btn bp mt8" onClick={()=>setTab("generate")}>使用已選話題生成內容 →</button>}
                </>}
              </div>
            </div>

          ) : tab==="generate" ? (
            /* ═══ GENERATE ═══ */
            <div className="fin">
              {selTopics.length>0&&<div className="cd" style={{borderLeft:"3px solid var(--ac)"}}><div style={{fontSize:11,fontWeight:600,color:"var(--ac)",marginBottom:6}}>從「探索話題」已選</div><div className="cg">{selTopics.map(i=><span key={i} className="ch on">{trends[i]?.title}</span>)}</div></div>}

              <div className="cd">
                <div className="cd-t">✏️ 內容方向</div>
                <div style={{fontSize:11,color:"var(--t3)",marginBottom:10}}>可以用上面已選話題，或自己填寫想寫嘅內容。兩者都填嘅話以自訂為主。</div>
                <div className="fg"><label className="fl">想寫咩內容？（自訂主題）</label><textarea className="ft" value={customBrief} onChange={e=>setCustomBrief(e.target.value)} placeholder="例：介紹我哋新推出嘅手沖咖啡工作坊，每週六下午舉行，適合初學者..." style={{minHeight:56}}/></div>
                <div className="fg"><label className="fl">內容目標（可選）</label><input className="fi" value={customGoal} onChange={e=>setCustomGoal(e.target.value)} placeholder="例：吸引報名、提升品牌知名度、引導去門市消費..."/></div>
              </div>

              <div className="cd"><div className="cd-t">選擇平台</div><div className="pg">{PLATFORMS.map(p=><div key={p.id} className={`pc ${plat===p.id?"on":""}`} style={{color:plat===p.id?p.color:"var(--t2)"}} onClick={()=>{setPlat(p.id);setFmt("");}}><div className="pi" style={{background:plat===p.id?p.color:"var(--b4)",color:plat===p.id?"#fff":"var(--t3)"}}>{p.icon}</div><div className="pn">{p.name}</div></div>)}</div></div>

              {plat&&<div className="cd fin">
                <div className="cd-t">內容設定</div>
                <div className="r2">
                  <div className="fg"><label className="fl">格式</label><select className="fs" value={fmt} onChange={e=>setFmt(e.target.value)}><option value="">選擇</option>{PLATFORMS.find(p=>p.id===plat)?.formats.map(f=><option key={f}>{f}</option>)}</select></div>
                  <div className="fg"><label className="fl">語言</label><select className="fs" value={lang} onChange={e=>setLang(e.target.value)}>{LANGUAGES.map(l=><option key={l.id} value={l.id}>{l.name}</option>)}</select></div>
                </div>
                <div className="fg"><label className="fl">長度</label><div className="cg">{LENGTHS.map(l=><button key={l.id} className={`ch ${len===l.id?"on":""}`} onClick={()=>setLen(l.id)}>{l.name}({l.desc})</button>)}</div></div>

                {templates.length>0&&<div className="fg"><label className="fl">套用 Prompt 模板</label><div className="cg">{templates.map(t=><button key={t.id} className="ch" onClick={()=>generate(t.prompt)}>{t.name}</button>)}</div></div>}

                <button className="btn bp mt8" onClick={()=>generate()} disabled={!fmt||genLoad}>{genLoad?"生成中...":"✨ 生成內容"}</button>
              </div>}

              {genLoad&&<Loading text="AI 生成內容中..."/>}

              {output&&!genLoad&&<div className="cd fin">
                <div className="oh"><div className="gap6"><span className="opb" style={{background:PLATFORMS.find(p=>p.id===plat)?.color}}>{PLATFORMS.find(p=>p.id===plat)?.icon} {PLATFORMS.find(p=>p.id===plat)?.name}</span><span style={{fontSize:10,color:"var(--t3)"}}>{fmt}·{LANGUAGES.find(l=>l.id===lang)?.name}</span></div><button className="cpb" onClick={()=>copy(output)}>{copied?"✓ 已複製":"複製"}</button></div>
                <div className="ob">{output}</div>

                <div className="gap8 mt12">
                  <button className="btn bs bsm" onClick={()=>generate()}>🔄 重新生成</button>
                  <button className="btn bs bsm" onClick={suggestImages} disabled={imgLoad}>{imgLoad?"分析中...":"🎨 AI 配圖建議"}</button>
                  <button className="btn bs bsm" onClick={multiRewrite} disabled={multiLoad}>{multiLoad?"改寫中...":"📱 多平台一鍵改寫"}</button>
                  <button className="btn bs bsm" onClick={()=>setScheduleItem({content:output,platform:plat,format:fmt})}>📅 排入日曆</button>
                </div>
              </div>}

              {/* AI Image Suggestions */}
              {imgLoad&&<Loading text="AI 分析配圖方向..."/>}
              {imgSugs.length>0&&<div className="cd fin">
                <div className="cd-t">🎨 AI 配圖建議</div>
                <div className="img-sug">{imgSugs.map((s,i)=><div key={i} className="img-card"><div style={{fontSize:13,fontWeight:600,marginBottom:4}}>{s.direction}</div><div style={{fontSize:11,color:"var(--t2)",lineHeight:1.4,marginBottom:6}}>{s.description}</div><div style={{fontSize:10,color:"var(--t3)",marginBottom:4}}>風格：{s.style}</div><div style={{background:"var(--b4)",borderRadius:5,padding:8,fontSize:10,color:"var(--ac)",lineHeight:1.4,wordBreak:"break-all"}}><div style={{fontSize:9,color:"var(--t3)",marginBottom:3}}>Midjourney Prompt:</div>{s.midjourney_prompt}</div><button className="cpb mt8" style={{fontSize:10}} onClick={()=>copy(s.midjourney_prompt)}>複製 Prompt</button></div>)}</div>
              </div>}

              {/* Multi-platform outputs */}
              {multiLoad&&<Loading text="改寫為5個平台版本..."/>}
              {multiOutputs.length>0&&<div className="cd fin">
                <div className="cd-t">📱 多平台版本</div>
                {multiOutputs.map((o,i)=><div key={i} style={{marginBottom:12}}><div className="gap6 mb8"><span className="opb" style={{background:PLATFORMS.find(p=>p.name===o.platform||p.id===o.platform)?.color||"#555"}}>{o.platform}</span><span style={{fontSize:10,color:"var(--t3)"}}>{o.format}</span><button className="cpb" onClick={()=>copy(o.content)}>複製</button></div><div className="ob" style={{minHeight:80,fontSize:12}}>{o.content}</div></div>)}
              </div>}
            </div>

          ) : tab==="calendar" ? (
            /* ═══ CALENDAR ═══ */
            <div className="fin">
              <div className="cd">
                <div className="between mb12">
                  <div style={{display:"flex",alignItems:"center",gap:12}}>
                    <div className="cd-t" style={{margin:0}}>{calMonth.y}年 {monthNames[calMonth.m]}</div>
                    <span style={{fontSize:11,color:"var(--t3)",background:"var(--b3)",padding:"2px 8px",borderRadius:4}}>{calEvents.filter(e=>{const d=new Date(e.date);return d.getMonth()===calMonth.m&&d.getFullYear()===calMonth.y;}).length} 個排期</span>
                  </div>
                  <div className="gap6">
                    <button className="btn bs bsm" onClick={()=>setCalMonth(p=>{const m=p.m-1;return m<0?{y:p.y-1,m:11}:{y:p.y,m};})}>◀</button>
                    <button className="btn bs bsm" onClick={()=>{const d=new Date();setCalMonth({y:d.getFullYear(),m:d.getMonth()});}}>今天</button>
                    <button className="btn bs bsm" onClick={()=>setCalMonth(p=>{const m=p.m+1;return m>11?{y:p.y+1,m:0}:{y:p.y,m};})}>▶</button>
                  </div>
                </div>
                <div className="cal-grid">
                  {["日","一","二","三","四","五","六"].map(d=><div key={d} className="cal-hd">{d}</div>)}
                  {calDays.map((d,i)=>{
                    const dateStr=d.cur?`${calMonth.y}-${String(calMonth.m+1).padStart(2,"0")}-${String(d.d).padStart(2,"0")}`:"";
                    const evts=calEvents.filter(e=>e.date===dateStr);
                    const isToday=d.cur&&d.d===today.getDate()&&calMonth.m===today.getMonth()&&calMonth.y===today.getFullYear();
                    return <div key={i} className={`cal-d ${isToday?"today":""} ${!d.cur?"other":""} ${evts.length>0?"has-ev":""}`} onClick={()=>{if(d.cur) setScheduleItem({date:dateStr,content:"",platform:"facebook",format:"",title:""});}}>
                      <div className="cal-dn">{d.d}</div>
                      {evts.length>2&&<div className="cal-count">{evts.length}</div>}
                      {evts.slice(0,2).map(e=><div key={e.id} className="cal-ev" style={{background:PLATFORMS.find(p=>p.id===e.platform)?.color||"#555"}} onClick={(ev)=>{ev.stopPropagation();if(confirm("刪除「"+e.title+"」？"))delCalEvent(e.id);}}>{e.title||e.platform}</div>)}
                      {evts.length>2&&<div style={{fontSize:8,color:"var(--t3)",textAlign:"center"}}>+{evts.length-2} 更多</div>}
                    </div>;
                  })}
                </div>
                <div style={{fontSize:10,color:"var(--t3)",marginTop:10,display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
                  <span>點擊日期新增排期</span>
                  <span style={{display:"flex",alignItems:"center",gap:4,color:"var(--t3)"}}>平台色標：</span>
                  {PLATFORMS.map(p=><span key={p.id} style={{display:"inline-flex",alignItems:"center",gap:3,fontSize:9}}><span style={{width:8,height:8,borderRadius:2,background:p.color,display:"inline-block"}}/>{p.name}</span>)}
                </div>
              </div>

              <div className="cd">
                <div className="between mb12">
                  <div className="cd-t" style={{margin:0}}>即將發佈</div>
                  <span style={{fontSize:11,color:"var(--t3)"}}>{calEvents.filter(e=>new Date(e.date)>=today).length} 個待發</span>
                </div>
                {calEvents.filter(e=>new Date(e.date)>=today).sort((a,b)=>new Date(a.date)-new Date(b.date)).map(e=>{
                  const d=new Date(e.date+"T00:00:00");
                  const diffDays=Math.ceil((d-new Date(today.toDateString()))/86400000);
                  const weekdays=["週日","週一","週二","週三","週四","週五","週六"];
                  const urgentColor=diffDays<=1?"var(--red)":diffDays<=3?"var(--ac)":"var(--t3)";
                  return <div key={e.id} className="upcoming-item">
                    <div className="upcoming-date">
                      <div className="upcoming-day" style={{color:diffDays<=1?"var(--red)":"var(--t1)"}}>{d.getDate()}</div>
                      <div className="upcoming-month">{monthNames[d.getMonth()]}</div>
                      <div className="upcoming-weekday">{weekdays[d.getDay()]}</div>
                    </div>
                    <div>
                      <div style={{fontSize:13,fontWeight:600,marginBottom:3}}>{e.title}</div>
                      <div className="gap6">
                        <span className="opb" style={{background:PLATFORMS.find(p=>p.id===e.platform)?.color||"#555"}}>{PLATFORMS.find(p=>p.id===e.platform)?.name||e.platform}</span>
                        <span style={{fontSize:10,color:urgentColor,fontWeight:600}}>{diffDays===0?"今天！":diffDays===1?"明天":diffDays+"天後"}</span>
                      </div>
                      {e.note&&<div style={{fontSize:10,color:"var(--t3)",marginTop:3}}>{e.note}</div>}
                    </div>
                    <button className="cpb" onClick={()=>delCalEvent(e.id)} style={{alignSelf:"start"}}>✕</button>
                  </div>;
                })}
                {calEvents.filter(e=>new Date(e.date)>=today).length===0&&<div className="es" style={{padding:"30px 20px"}}><div className="es-i">📅</div><h3>暫無排期</h3><p>生成內容後點「排入日曆」，或直接點擊日曆上的日期新增。</p></div>}
              </div>
            </div>

          ) : tab==="history" ? (
            /* ═══ HISTORY ═══ */
            <div className="fin">
              <div className="cd">
                <div className="between mb12"><div className="cd-t" style={{margin:0}}>內容歷史記錄</div><div style={{fontSize:11,color:"var(--t3)"}}>{history.length} 條記錄</div></div>
                {history.length===0?<div style={{fontSize:12,color:"var(--t3)"}}>尚未生成內容</div>:
                history.map(h=><div key={h.id} className="hi" onClick={()=>setHistoryView(h)}><div className="between"><div className="gap6"><span className="opb" style={{background:PLATFORMS.find(p=>p.id===h.platform)?.color||"#555"}}>{h.platform}</span><span style={{fontSize:10,color:"var(--t3)"}}>{h.format}</span>{h.topics?.map((t,i)=><span key={i} className="tg">{t}</span>)}</div><span style={{fontSize:10,color:"var(--t3)"}}>{new Date(h.date).toLocaleDateString("zh-TW")}</span></div><div style={{fontSize:11,color:"var(--t2)",marginTop:5,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{h.content?.substring(0,100)}</div></div>)}
              </div>
            </div>

          ) : tab==="templates" ? (
            /* ═══ TEMPLATES ═══ */
            <div className="fin">
              <div className="cd">
                <div className="between mb12"><div className="cd-t" style={{margin:0}}>Prompt 模板</div><button className="btn bp bsm" onClick={()=>{setEditTpl(null);setModal("template");}}>+ 新增模板</button></div>
                <div style={{fontSize:11,color:"var(--t3)",marginBottom:10}}>建立常用的 Prompt 指令模板，生成內容時可一鍵套用。</div>
                {templates.length===0?<div className="es"><div className="es-i">📝</div><h3>建立你的第一個模板</h3><p>儲存常用 Prompt 指令，提升效率。</p></div>:
                templates.map(t=><div key={t.id} className="hi" onClick={()=>{setEditTpl(t);setModal("template");}}><div className="between"><div><div style={{fontSize:13,fontWeight:600}}>{t.name}</div><div style={{fontSize:11,color:"var(--t3)",marginTop:2}}>{t.description}</div></div><button className="cpb" onClick={e=>{e.stopPropagation();delTpl(t.id);}}>刪除</button></div><div style={{fontSize:11,color:"var(--t2)",marginTop:6,background:"var(--b4)",padding:8,borderRadius:5,lineHeight:1.4}}>{t.prompt?.substring(0,150)}...</div></div>)}
              </div>
            </div>

          ) : tab==="competitors" ? (
            /* ═══ COMPETITORS ═══ */
            <div className="fin">
              <div className="cd">
                <div className="cd-t">競爭對手名單</div>
                <div style={{fontSize:11,color:"var(--t3)",marginBottom:10}}>加入你想追蹤嘅競爭對手品牌，AI 會針對性分析佢哋嘅社交媒體策略。</div>

                <div style={{display:"flex",gap:6,marginBottom:12}}>
                  <input className="fi" value={compInput} onChange={e=>setCompInput(e.target.value)} placeholder="輸入競爭對手名稱，例：Starbucks" onKeyDown={e=>{if(e.key==="Enter"&&compInput.trim()){addComp(compInput);setCompInput("");}}} style={{flex:1}}/>
                  <button className="btn bp bsm" disabled={!compInput.trim()} onClick={()=>{addComp(compInput);setCompInput("");}}>+ 加入</button>
                </div>

                {compList.length>0 ? (
                  <div className="cg mb12">{compList.map(name=><span key={name} className="ch on" style={{display:"inline-flex",alignItems:"center",gap:6}}>{name}<span style={{cursor:"pointer",opacity:.6,fontSize:14,lineHeight:1}} onClick={()=>removeComp(name)}>×</span></span>)}</div>
                ) : (
                  <div style={{fontSize:11,color:"var(--t3)",marginBottom:12,padding:"10px 0",borderTop:"1px solid var(--bd)",borderBottom:"1px solid var(--bd)"}}>尚未加入任何競爭對手。你可以手動輸入，或直接點「分析」讓 AI 自動搜尋行業對手。</div>
                )}

                <button className="btn bp" onClick={trackCompetitors} disabled={compLoad}>
                  {compLoad?"分析中...": compList.length>0 ? `🎯 分析 ${compList.length} 個競爭對手` : "🎯 AI 自動搜尋行業對手"}
                </button>
              </div>

              {compLoad&&<Loading text="搜尋並分析競爭對手策略..."/>}

              {/* Data freshness indicator */}
              {compMeta&&!compLoad&&<div className="fin" style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 14px",marginBottom:12,borderRadius:8,background:compMeta.source==="live"?"rgba(34,197,94,.08)":"rgba(239,68,68,.08)",border:`1px solid ${compMeta.source==="live"?"rgba(34,197,94,.2)":"rgba(239,68,68,.2)"}`}}>
                <div style={{display:"flex",alignItems:"center",gap:8}}>
                  <span className="dot" style={{background:compMeta.source==="live"?"var(--grn)":"var(--red)"}}/>
                  <span style={{fontSize:11,fontWeight:600,color:compMeta.source==="live"?"var(--grn)":"var(--red)"}}>{compMeta.source==="live"?"即時網絡搜尋":"AI 知識庫（非即時）"}</span>
                  <span style={{fontSize:10,color:"var(--t3)"}}>·</span>
                  <span style={{fontSize:10,color:"var(--t3)"}}>{compMeta.source==="live"?"已透過 Web Search 獲取最新公開資料":"Web Search 未能連接，使用 AI 訓練數據（截至 2025 年中）"}</span>
                </div>
                <span style={{fontSize:10,color:"var(--t3)",whiteSpace:"nowrap"}}>{compMeta.time}</span>
              </div>}

              {/* Self Analysis - Our Brand */}
              {selfAnalysis&&<div className="cd fin" style={{borderLeft:"3px solid var(--ac)",background:"var(--ac08)"}}>
                <div className="between mb8">
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <div className="ca" style={{background:CC[ac.category]||"#555",width:26,height:26,fontSize:11}}>{ac.name[0]}</div>
                    <div style={{fontSize:16,fontWeight:700}}>{ac.name}</div>
                    <span className="tag" style={{background:"var(--ac)",color:"#0A0A0B",fontSize:9}}>我方</span>
                  </div>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginTop:10}}>
                  <div><div className="fl">📋 現時內容策略</div><div style={{fontSize:12,color:"var(--t1)",lineHeight:1.5}}>{selfAnalysis.strategy}</div></div>
                  <div><div className="fl">💪 優勢</div><div style={{fontSize:12,color:"var(--grn)",lineHeight:1.5}}>{selfAnalysis.strength}</div></div>
                  <div><div className="fl">⚠️ 需改善</div><div style={{fontSize:12,color:"var(--red)",lineHeight:1.5,opacity:.85}}>{selfAnalysis.weakness}</div></div>
                  <div><div className="fl">🎯 首要建議</div><div style={{fontSize:12,color:"var(--ac)",lineHeight:1.5}}>{selfAnalysis.recommendation}</div></div>
                </div>
              </div>}

              {/* Competitor Cards */}
              {compResults.length>0&&<div className="cd fin">
                <div className="cd-t">競爭對手分析</div>
                <div className="r2">{compResults.map((c,i)=><div key={i} className="cd" style={{margin:0}}>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                    <div style={{width:26,height:26,borderRadius:5,background:"var(--b4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,color:"var(--t2)"}}>{c.competitor?.[0]||"?"}</div>
                    <div style={{fontSize:14,fontWeight:700}}>{c.competitor}</div>
                    <span className="tag" style={{background:"rgba(255,255,255,.08)",color:"var(--t3)",fontSize:9}}>對手</span>
                  </div>
                  <div className="tg mb8">{c.platform}</div>
                  <div className="fg"><div className="fl">內容策略</div><div style={{fontSize:12,color:"var(--t2)",lineHeight:1.4}}>{c.strategy}</div></div>
                  <div className="fg"><div className="fl">優勢</div><div style={{fontSize:12,color:"var(--grn)",lineHeight:1.4}}>{c.strength}</div></div>
                  <div className="fg"><div className="fl">💡 我們的機會</div><div style={{fontSize:12,color:"var(--ac)",lineHeight:1.4}}>{c.opportunity}</div></div>
                  <div style={{fontSize:10,color:"var(--t3)"}}>趨勢：{c.trend}</div>
                </div>)}</div>
              </div>}
            </div>
          ) : null}
        </div>
      </div>
    </div>

    {/* MODALS */}
    {modal==="client"&&<ClientModal client={editCl} onSave={saveCl} onClose={()=>{setModal(null);setEditCl(null);}} onDelete={delCl}/>}

    {modal==="template"&&<TemplateModal tpl={editTpl} onSave={saveTpl} onClose={()=>{setModal(null);setEditTpl(null);}}/>}

    {scheduleItem&&<ScheduleModal item={scheduleItem} onSave={(ev)=>{addCalEvent(ev);setScheduleItem(null);}} onClose={()=>setScheduleItem(null)} clientName={ac?.name} clientCategory={ac?.category}/>}

    {historyView&&<Modal title="內容詳情" onClose={()=>setHistoryView(null)} width="560px">
      <div className="gap6 mb12"><span className="opb" style={{background:PLATFORMS.find(p=>p.id===historyView.platform)?.color||"#555"}}>{historyView.platform}</span><span style={{fontSize:10,color:"var(--t3)"}}>{historyView.format} · {new Date(historyView.date).toLocaleDateString("zh-TW")}</span></div>
      <div className="ob" style={{maxHeight:400,overflow:"auto"}}>{historyView.content}</div>
      <div className="md-a"><button className="btn bs" onClick={()=>setHistoryView(null)}>關閉</button><button className="btn bp" onClick={()=>{copy(historyView.content);}}>{copied?"✓ 已複製":"複製內容"}</button></div>
    </Modal>}
  </>);
}
